var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Hmm...","TWN":"唔……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"더 내려갈 데가 없네요. 여기가 제일 아래층인가 봐요.","JPN":"これ以上下りるところはないようですね。ここが一番下の階みたいです。","ENG":"We can't go down any further. This must be the bottom floor.","TWN":"不能再往下走了。這裡好像是最後一層。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"괜히 내려왔군. 위층과 다르게 이터니움은커녕 잡동사니 하나 없어.","JPN":"無駄だったな。上の階と違ってエタニウムどころか、がらくた一つすらない。","ENG":"Looks like we came down here for nothing. Unlike upstairs, there's hardly a piece of junk down here, let alone Eternium.","TWN":"白下來了。跟上層不同，別說永恆之金了，連個雜物都沒有。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다시 돌아갈까요? 길이 닫히기 전에 돌아가야 한다고 들었어요.","JPN":"戻りますか？　道が閉ざされる前に戻らなければならないと聞きました。","ENG":"Should we go back up? I heard we have to get back before the path closes.","TWN":"要回去嗎？聽說要在通道關閉之前回去。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"위에 이터니움이 무지 많았으니까, 전부 실으려면 저희도 도와야 할 거예요!","JPN":"上はエタニウムが山ほどあったから、すべて運ぶんだったら私たちも手伝わないと！","ENG":"There's tons of Eternium up there. They'll probably need our help loading it all up!","TWN":"上面的永恆之金那麼多，要全部裝上的話我們也要幫忙才行呢！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런데 언니, 정말로 여기서 얻은 이터니움이랑 아티팩트까지 전부 가져갈 거예요?","JPN":"でもリタお姉ちゃん、本当にここで手にしたエタニウムとアーティファクトを全部うちの会社に持って帰るんですか？","ENG":"By the way, are you really going to take all the Eternium and Artifacts from here?","TWN":"但是姐姐，真的要把這裡的永恆之金和人造神器全部拿走嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"윌버는 그 정도 협박은 해야 알아듣는 놈이야.","JPN":"ウィルバーはそれくらい脅しておかないと、聞く耳を持たないからな。","ENG":"A threat like that is the only way to knock some sense into that Wilbur fool.","TWN":"對待韋爾伯那種傢伙，只有那麼說他才能聽得進去。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐, 헛소리에 어울려 준 것치고는 제법 괜찮은 소득이었지.","JPN":"まあ、バカな夢物語に付き合ってやったわりには悪くない収穫だ。","ENG":"I guess humoring that crazy guy turned out to be more lucrative than expected.","TWN":"雖說是胡說嚇嚇他的，多虧他們也一本正經默默的接受了，收穫還算不錯。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"돌아간 후에 자기가 한 일을 반성한다면 연구비 정도는 챙겨줄 수도......","JPN":"戻った後、奴がやらかしたことを反省するなら研究費ぐらいは渡してあげても……","ENG":"If he shows any sign of remorse for what he's done, maybe I'll consider covering his research expenses...","TWN":"回去之後，如果他能對自己的所作所為好好反省，那我也可以支援一些研究費……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>......이리로 오라.</color>","JPN":"<color=#ff3636>……こちらへ来い。</color>","ENG":"<color=#ff3636>Come hither...</color>","TWN":"<color=#ff3636>……過來這裡。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......응?","JPN":"……ん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니? 왜 그래요?","JPN":"リタお姉ちゃん？　どうしたんですか？","ENG":"Rita? What is it?","TWN":"姐姐？你怎麼了？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"조용히 있어 봐. 방금 무슨 소리가 들렸어.","JPN":"静かに。声が聞こえた。","ENG":"Shh. I think I just heard something.","TWN":"安靜點，我剛剛好像聽到了什麼聲音。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"소리요? 저한테는 하나도 안 들렸는데?","JPN":"声ですか？　私には何も聞こえなかったですが……","ENG":"Heard what? I didn't hear anything.","TWN":"聲音？我怎麼什麼都沒聽到？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>우리의 자매가 될 자여. 이리로 오라.</color>","JPN":"<color=#ff3636>我が姉妹となる者よ。こちらへ来い。</color>","ENG":"<color=#ff3636>Ye who shall be our sister. Come hither.</color>","TWN":"<color=#ff3636>即將成為我們姐妹的人，過來吧。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이쪽인가?","JPN":"こっちか？","ENG":"Is it this way?","TWN":"是這邊嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"벽은...... 그렇게 두텁진 않은 것 같군.","JPN":"壁はそんなに……厚くないようだな。","ENG":"This wall... doesn't seem that thick.","TWN":"牆……好像沒那麼厚。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"에엣취!","JPN":"はくしょん！","ENG":"Achoo!","TWN":"哎哎呀！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어, 언니! 먼지 때문에 눈을 못 뜨겠어요!","JPN":"リ、リタお姉ちゃん！　埃のせいで目が開けられません！","ENG":"R-Rita! I can't open my eyes with all this dust!","TWN":"呃，姐姐！灰塵好多，我都睜不開眼睛了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내 손 잡고 따라와. 안에 공간이 있어.","JPN":"手を握ってついて来い。中に空間がある。","ENG":"Just hold my hand and follow me. There's another space inside.","TWN":"牽著我的手跟上，裡面有空間。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우와...... 여긴 무슨 실험을 하던 곳인가 봐요.","JPN":"わあ……ここは何かの実験室だったみたいですね。","ENG":"Whoa... They seemed to have conducted some kind of an experiment here.","TWN":"嗚哇……這裡好像是進行什麼實驗的地方。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 하지만 이상하군.","JPN":"そうだな。しかし妙だな。","ENG":"Right. But it's strange.","TWN":"嗯，但有些奇怪。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이상하다니요?","JPN":"何がおかしいんですか？","ENG":"What's strange?","TWN":"奇怪？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"방금 그 기분 나쁜 목소리가 들리기 전까지는 이런 공간이 있는지 전혀 못 알아챘어.","JPN":"さっきの気味が悪い声が聞こえるまで、こんな空間があることに気付かなかった。","ENG":"I didn't realize there was a place like this until I heard that creepy voice just now.","TWN":"在聽到剛才那個令人不愉的聲音之前，我根本就沒注意到有這樣的空間。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그리고 너무 멀쩡해. 침식체들이 이런 어둡고 폐쇄된 공간을 놔둘 리 없는데.","JPN":"それに、あまりにも状態がいい。侵食体がこんな暗くて閉鎖された空間を放っておくはずがないのに。","ENG":"And it's in perfectly fine shape. There's no way the C.O.s would leave such a dark, enclosed place alone.","TWN":"而且這裡太完善了。侵蝕體正常情況下不可能放過這種黑暗又封閉的空間才對。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"봐. 서류들도 책상에 멀쩡히 놓여 있잖아.","JPN":"ほら、書類も机にきちんと置いてある。","ENG":"See? Even the documents are neatly organized on the desk.","TWN":"看，各種檔案也好好地放在桌子上。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말이네요. 버려진 뒤로 아무도 안 건드린 것 같아요.","JPN":"本当だ。建物が放置されてから誰の手にも触れられていないみたいです。","ENG":"You're right. It's as if no one touched this place since it was abandoned.","TWN":"真的誒。好像是廢棄之後就一直沒人來過。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"우리에겐 행운이지. 이런 종이 뭉치도 비싼 값에 사는 것들이 있거든.","JPN":"これはラッキーだ。こんな紙束でも、裏世界の物ってだけで高値で買ってくれる奴がいるからな。","ENG":"Lucky for us. There are fools who'd pay a fortune for even a stack of papers like this.","TWN":"對我們來說是幸運。這種紙團也有人高價收購呢。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>......전선은 교착 상태를 이어가고 있다. 하지만 병력은 나날이 부족해져만 가고 있다.</color>","JPN":"<color=#ffd34c>……戦線は膠着状態が続いている。しかし、兵力は日に日に不足していく。</color>","ENG":"<color=#ffd34c>... The front lines remain at a stalemate. But the troop shortage seems to get worse each day.</color>","TWN":"<color=#ffd34c>戰況一直處於膠著狀態，但兵力日益不足。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>......께서 용단을 내리셨다. 카운터를 양산하기 위해서는 모든 수단을 동원해야 한다.</color>","JPN":"<color=#ffd34c>……は勇断を下した。カウンターを量産するためにはあらゆる手段を尽くさねばならない。</color>","ENG":"<color=#ffd34c>... has made a decision. We must use all means possible to mass-produce Counters.</color>","TWN":"<color=#ffd34c>……下了最終判斷。必須採取一切手段批量生產制裁者。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>멘탈 프린팅에 기반한 복제 기술이 마지막 희망이다. 더 이상 물러설 곳은 없다.</color>","JPN":"<color=#ffd34c>メンタルプリンティングに基づいた複製技術が最後の希望だ。もう後戻りはできない。</color>","ENG":"<color=#ffd34c>The cloning technology based on Mental Printing is our final hope. We cannot retreat any further.</color>","TWN":"<color=#ffd34c>基於精神複製的克隆技術是最後的希望。已經沒有退路了。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>......수정체에 마지막 난관을 넘기 위한 해답이 숨겨져 있다.</color>","JPN":"<color=#ffd34c>……水晶に最後の難関を越えるための解答が隠されている。</color>","ENG":"<color=#ffd34c>... The crystalline structure bears the answer to overcome the final hurdle.</color>","TWN":"<color=#ffd34c>……水晶體中隱藏著可以渡過最後難關的答案。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것으로...... 전황은 바뀌리라.</color>","JPN":"<color=#ffd34c>これで……戦況は変わるはず。</color>","ENG":"<color=#ffd34c>And with this... the tide of the battle may turn.</color>","TWN":"<color=#ffd34c>要用這個……扭轉戰局。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아니, 반드시 바뀌어야 한다.</color>","JPN":"<color=#ffd34c>いや、変えなければならない。</color>","ENG":"<color=#ffd34c>No... it MUST turn.</color>","TWN":"<color=#ffd34c>不，必須成功。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......카운터를 양산해? 내가 아는 것과 다른 의미인가?","JPN":"……カウンターを量産する？　どういう意味だ？","ENG":"Mass-produce Counters? Does this mean what I think it means?","TWN":"……量產制裁者？難道跟我知道的不一樣？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니! 여기 와 보세요!","JPN":"リタお姉ちゃん！　これを見てください！","ENG":"Rita! Come here!","TWN":"麗塔姐姐！快來看看這裡！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니가 말했던 돈 될 거리를 찾은 것 같아요!","JPN":"お金になりそうな物を見つけました！","ENG":"I think I found something worthwhile, like you said!","TWN":"我好像找到了姐姐說的值錢的東西！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이건...... 수정이군.","JPN":"これは……水晶か。","ENG":"This... is a crystal.","TWN":"這是……水晶。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"엄청 커다랗고 색도 예쁜 보석이니까 분명 비싼 값에 팔릴 거예요.","JPN":"とても大きくて色も綺麗だし、きっと高値で売れると思いますよ。","ENG":"I'm sure a huge, pretty gem like this will fetch a handsome price.","TWN":"又大又漂亮的寶石，肯定能賣個好價錢。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"좋아. 위험을 감수해서라도 가져 갈 가치는 있겠어.","JPN":"よし。リスクを冒してでも持って帰る価値はありそうだな。","ENG":"Good. This should be worth the risk of taking it back with us.","TWN":"很好，即使有危險也值得冒險一試。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗! 방금 칭찬해 주신 거 맞죠?!","JPN":"あ！　今褒めてくれたんですよね！？","ENG":"Oh! Was that a compliment just now?","TWN":"啊！你是在稱讚我嗎？！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"넌 왜 그렇게 칭찬 받고 싶어서 안달이야?","JPN":"お前はどうしてそんなに褒められたがるんだ？","ENG":"Why are you always so eager for compliments?","TWN":"你為什麼那麼想得到稱讚？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"칭찬을 들으면 힘이 쑥쑥 솟아나거든요. 불가능한 일도 어떻게든 해낼 수 있을 것 같아져요.","JPN":"だって褒められたらやる気がぐんぐん上がるんです！　出来ないことだってやれる気持ちになりますよ。","ENG":"They really cheer me up, you see. They make me feel like I can do the impossible.","TWN":"得到稱讚我就充滿力量。好像不可能的事情也能做到。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그럼 앞으로도 칭찬은 없어. 무모하게 굴다가 개죽음 당하면 곤란하니까.","JPN":"じゃあこれからも褒め言葉は無しだ。そのやる気で無茶されて無駄死にしたら困るからな。","ENG":"Then I won't compliment you anymore. I can't have you getting reckless and dying.","TWN":"那今後我不會再稱讚你了。你如果魯莽行事橫死街頭就麻煩了。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"맘에 들진 않지만 감정을 하려면 윌버가 필요하겠군. 위에 연락해 봐.","JPN":"気に入らないが、鑑定にはウィルバーが必要だな。上の階に連絡してくれ。","ENG":"I'd hate to do this, but I'll need Wilbur to appraise the crystal. See if you can reach him up there.","TWN":"雖然不喜歡，但要驗證只能靠韋爾伯了，聯繫一下上面吧。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹!","JPN":"はいっ！","ENG":"Oki!","TWN":"是！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>비상. 출입 통제 구역에서 미인가 전파 감지. 내부 보안 규정에 근거해 진압을 시작합니다.</color>","JPN":"<color=#ffd34c>非常事態発生。立入統制区域で非認可電波を感知。内部セキュリティ規程に基づき鎮圧を開始します。</color>","ENG":"<color=#ffd34c>ALERT. Unauthorized transmission detected in the restricted access area. Initiating security protocol.</color>","TWN":"<color=#ffd34c>緊急情況。在出入管制區域檢測到未認可電波。根據內部安全規定開始實施鎮壓。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐? 이렇게 오래된 곳인데 보안 시스템이 작동한다고?","JPN":"は？　こんな古い建物でセキュリティシステムが作動するだと？","ENG":"What? The security system's working in an old beat-up place like this?","TWN":"什麼？這麼古老的地方竟然還能啟動保安系統？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니! 저기 보세요!","JPN":"リタお姉ちゃん！　あそこを見てください！","ENG":"Rita! Look!","TWN":"麗塔姐姐！看那邊！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"TANK_STATE_NULL_CORRUPT","text":{"KOREA":"<color=#ff3636>박멸. 박멸하라. 더러운 힘을. 박멸하라.</color>","JPN":"<color=#ff3636>撲滅。撲滅せよ。汚らわしい力を。撲滅せよ。</color>","ENG":"<color=#ff3636>EXTERMINATE. EXTERMINATE. EXTERMINATE THE UNCLEAN. EXTERMINATE.</color>","TWN":"<color=#ff3636>毀滅，毀滅。骯髒的力量。毀滅吧。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MECHANIC_RAZANGRIFF_SKILL_START"},{"id":"L32_1","type":"dialog","speaker":"TANK_STATE_NULL_CORRUPT","text":{"KOREA":"<color=#ff3636>멸망이 온다. 멸망의 전조. 박멸. 박멸.</color>","JPN":"<color=#ff3636>滅亡が来る。滅亡の予兆。撲滅。撲滅。</color>","ENG":"<color=#ff3636>The End is nigh. The signs of the End times. EXTERMINATE. EXTERMINATE.</color>","TWN":"<color=#ff3636>滅亡來臨。滅亡的前兆。毀滅吧。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 대표님보다 험악한 인공지능들이신 것 같아요!","JPN":"代表よりもガラの悪い人工知能みたいです！","ENG":"These A.I. seem an awful lot more aggressive than the boss!","TWN":"姐姐，好像是比BOSS還要兇惡的人工智慧！"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"침식체 대신 먼저 텃세를 부리던 놈들이 있었군......","JPN":"なるほど、侵食体よりも先に縄張りを張っていた連中がいたんだな……","ENG":"These guys must have been here long before the C.O.s...","TWN":"看來除了侵蝕體，這裡還有一些生氣的傢伙……"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뒤에 바짝 붙어 있어, 꼬맹이! 힘으로 돌파한다!","JPN":"私から離れるなよ、ガキ！　強行突破だ！","ENG":"Stay behind me, kid! We'll have to fight our way through!","TWN":"緊跟在我後面，小鬼！我要全力突圍！"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};